 public ServerStatus Status{get=>status;set{if(Set(ref status,value)){Raise(nameof(StatusText));Raise(nameof(StatusBrush));Raise(nameof(StatusTooltip));Raise(nameof(CanStart));Raise(nameof(CanStop));}}}public string StatusText=>Status.ToString();public string StatusTooltip=>$"{StatusText} — {Health}";public Brush StatusBrush=>Status switch{ServerStatus.Running=>Brushes.LimeGreen,ServerStatus.Starting or ServerStatus.Stopping or ServerStatus.Restarting=>Brushes.Goldenrod,ServerStatus.Failed or ServerStatus.Invalid=>Brushes.OrangeRed,ServerStatus.Stopped=>Brushes.SlateGray,_=>Brushes.DarkGray};
 public int? Pid{get=>pid;set{if(Set(ref pid,value)){Raise(nameof(CanStart));Raise(nameof(CanStop));}}}public TimeSpan Uptime{get=>uptime;set{if(Set(ref uptime,value))Raise(nameof(UptimeText));}}public string UptimeText=>Definition.Location==ServerLocation.Remote||Pid is not null?FormatDuration(Uptime):"—";public double Cpu{get=>cpu;set{if(Set(ref cpu,value))Raise(nameof(CpuText));}}public string CpuText=>$"{Cpu:F1}%";public long Memory{get=>memory;set{if(Set(ref memory,value))Raise(nameof(MemoryText));}}public string MemoryText=>$"{Memory/1048576d:F1} MB";public string Health{get=>health;set{if(Set(ref health,value))Raise(nameof(StatusTooltip));}}public string? LastError{get=>error;set=>Set(ref error,value);}public int? LastExitCode{get=>exit;set=>Set(ref exit,value);}public DateTime? Started{get=>started;set=>Set(ref started,value);}public DateTime? LastChecked{get=>lastChecked;set=>Set(ref lastChecked,value);}public DateTime? LastExitTime{get=>lastExitTime;set=>Set(ref lastExitTime,value);}public int RestartCount{get=>restartCount;set=>Set(ref restartCount,value);}public bool CanStart=>Definition.Location==ServerLocation.Local&&Definition.Enabled&&Pid is null&&Status is ServerStatus.Stopped or ServerStatus.Failed;public bool CanStop=>Definition.Location==ServerLocation.Local&&Pid is not null&&Status is ServerStatus.Running or ServerStatus.Starting or ServerStatus.Failed;public bool CanOpenLog=>Definition.Location==ServerLocation.Local&&!string.IsNullOrWhiteSpace(Definition.LogFilePath);public bool HasRawTelemetry=>!string.IsNullOrWhiteSpace(rawTelemetry);public string RawTelemetry=>rawTelemetry;public string RemoteMetricsSummary=>Definition.ServerType==ServerType.TibcoRendezvous?TibRvMetricsSummary:$"IDENTITY\nServer name: {Value(serverName)}\nServer ID: {Value(serverId)}\nVersion: {Value(serverVersion)}\nCluster: {Value(clusterName)}\nTags: {Value(serverTags)}\nMetadata: {Value(serverMetadata)}\nEndpoint: {Endpoint}\nHealth endpoint: {(healthEndpointHealthy?"Healthy":"Unavailable")}\n\nLOAD\nConnections: {connections:N0} / {(maximumConnections>0?maximumConnections.ToString("N0"):"unlimited")}\nTotal connections since start: {totalConnections:N0}\nSubscriptions: {subscriptions:N0}\nCPU: {CpuText}\nMemory: {MemoryText}\n\nTRAFFIC\nMessages/sec in / out: {inMessageRate:N1} / {outMessageRate:N1}\nBytes/sec in / out: {FormatRate(inByteRate)} / {FormatRate(outByteRate)}\nLifetime messages in / out: {inMessages:N0} / {outMessages:N0}\nLifetime bytes in / out: {FormatBytes(inBytes)} / {FormatBytes(outBytes)}\n\nTOPOLOGY\nRoutes: {routes:N0}\nRemotes: {remotes:N0}\nLeaf nodes: {leafNodes:N0}\n\nWARNINGS\nSlow consumers: {slowConsumers:N0}";string TibRvMetricsSummary=>$"IDENTITY\nComponent: {Value(serverName)}\nVersion: {Value(serverVersion)}\nHost: {Value(serverId)}\nService: {Value(clusterName)}\nNetwork: {Value(serverTags)}\nEndpoint: {Endpoint}\n\nLOAD\nClient connections: {connections:N0}\nSubscriptions: {subscriptions:N0}\nUptime: {UptimeText}\n\nTRAFFIC\nMessages/sec in / out: {inMessageRate:N1} / {outMessageRate:N1}\nBytes/sec in / out: {FormatRate(inByteRate)} / {FormatRate(outByteRate)}\nLifetime messages in / out: {inMessages:N0} / {outMessages:N0}\nLifetime bytes in / out: {FormatBytes(inBytes)} / {FormatBytes(outBytes)}\n\nDELIVERY WARNINGS\nInbound / outbound data loss: {routes:N0} / {remotes:N0}\nPackets retransmitted: {leafNodes:N0}\nPackets missed: {slowConsumers:N0}";public void ApplyTelemetry(RemoteServerTelemetry value){ApplyRates(value.SampleTime,value.InMessages,value.OutMessages,value.InBytes,value.OutBytes);serverId=value.ServerId;serverName=value.ServerName;serverVersion=value.Version;connections=value.Connections;subscriptions=value.Subscriptions;inMessages=value.InMessages;outMessages=value.OutMessages;inBytes=value.InBytes;outBytes=value.OutBytes;slowConsumers=value.SlowConsumers;maximumConnections=value.MaximumConnections;totalConnections=value.TotalConnections;routes=value.Routes;remotes=value.Remotes;leafNodes=value.LeafNodes;clusterName=value.ClusterName;serverTags=value.ServerTags;serverMetadata=value.ServerMetadata;healthEndpointHealthy=value.HealthEndpointHealthy;rawTelemetry=value.RawJson;FinishTelemetry(value.Uptime);}public void ApplyTelemetry(TibRvTelemetry value){ApplyRates(value.SampleTime,value.InMessages,value.OutMessages,value.InBytes,value.OutBytes);serverName=value.Component;serverVersion=value.Version;serverId=value.Host;clusterName=value.Service;serverTags=value.Network;connections=value.ClientConnections;subscriptions=value.Subscriptions;inMessages=value.InMessages;outMessages=value.OutMessages;inBytes=value.InBytes;outBytes=value.OutBytes;routes=(int)Math.Min(int.MaxValue,value.InDataLoss);remotes=(int)Math.Min(int.MaxValue,value.OutDataLoss);leafNodes=(int)Math.Min(int.MaxValue,value.RetransmittedPackets);slowConsumers=(int)Math.Min(int.MaxValue,value.MissedPackets);rawTelemetry=value.RawMetrics;FinishTelemetry(value.Uptime);}void ApplyRates(DateTimeOffset sample,long newInMessages,long newOutMessages,long newInBytes,long newOutBytes){if(previousSample.HasValue){var seconds=(sample-previousSample.Value).TotalSeconds;if(seconds>0){inMessageRate=Math.Max(0,(newInMessages-previousInMessages)/seconds);outMessageRate=Math.Max(0,(newOutMessages-previousOutMessages)/seconds);inByteRate=Math.Max(0,(newInBytes-previousInBytes)/seconds);outByteRate=Math.Max(0,(newOutBytes-previousOutBytes)/seconds);}}previousSample=sample;previousInMessages=newInMessages;previousOutMessages=newOutMessages;previousInBytes=newInBytes;previousOutBytes=newOutBytes;}void FinishTelemetry(TimeSpan value){Uptime=value;Started=DateTime.Now-value;Raise(nameof(RemoteMetricsSummary));Raise(nameof(RawTelemetry));Raise(nameof(HasRawTelemetry));}static string FormatDuration(TimeSpan value)=>value.TotalDays>=1?$"{(int)value.TotalDays}d {value.Hours}h":value.TotalHours>=1?$"{(int)value.TotalHours}h {value.Minutes}m":value.TotalMinutes>=1?$"{(int)value.TotalMinutes}m {value.Seconds}s":$"{Math.Max(0,(int)value.TotalSeconds)}s";static string FormatBytes(long value)=>value>=1073741824?$"{value/1073741824d:F1} GB":value>=1048576?$"{value/1048576d:F1} MB":value>=1024?$"{value/1024d:F1} KB":$"{value} B";static string FormatRate(double value)=>FormatBytes((long)value)+"/s";static string Value(string value)=>string.IsNullOrWhiteSpace(value)?"—":value;public void RefreshDefinition(){Raise(nameof(Name));Raise(nameof(TypeText));Raise(nameof(LocationText));Raise(nameof(Endpoint));Raise(nameof(ExecutableDisplay));Raise(nameof(PrimaryPort));Raise(nameof(Ports));Raise(nameof(PortsTooltip));Raise(nameof(LogFile));Raise(nameof(AutoStart));Raise(nameof(CanOpenLog));Raise(nameof(HasTelemetry));Raise(nameof(RowActionTooltip));Raise(nameof(RowActionGlyph));Raise(nameof(RemoteMetricsSummary));}
